import{_ as e,o,c as r,a7 as a}from"./chunks/framework.BPD8m7Vq.js";const u=JSON.parse('{"title":"🛠️ Java 核心神器：StringBuilder 完全指南","description":"","frontmatter":{"tags":["Java基础","核心类库","字符串处理","性能优化"],"date":"2026-03-01T00:00:00.000Z"},"headers":[],"relativePath":"Code/DS/StringBuilder.md","filePath":"Code/DS/StringBuilder.md","lastUpdated":1772337112000}'),d={name:"Code/DS/StringBuilder.md"};function l(n,t,i,s,c,g){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="🛠️-java-核心神器-stringbuilder-完全指南" tabindex="-1">🛠️ Java 核心神器：StringBuilder 完全指南 <a class="header-anchor" href="#🛠️-java-核心神器-stringbuilder-完全指南" aria-label="Permalink to &quot;🛠️ Java 核心神器：StringBuilder 完全指南&quot;">​</a></h1><blockquote><p>[!abstract] 核心定义 <code>StringBuilder</code> 是 Java 中用于处理<strong>可变字符串</strong>的核心类。 与绝对不可变的 <code>String</code> 不同，<code>StringBuilder</code> 允许你在<strong>原内存地址</strong>上直接对字符进行追加、插入、删除和修改，极大地节省了内存开销并提升了运行速度。</p></blockquote><hr><h2 id="🧠-底层原理解析-为什么它这么快" tabindex="-1">🧠 底层原理解析 (为什么它这么快？) <a class="header-anchor" href="#🧠-底层原理解析-为什么它这么快" aria-label="Permalink to &quot;🧠 底层原理解析 (为什么它这么快？)&quot;">​</a></h2><p>理解 <code>StringBuilder</code>，只需要记住它的两个核心物理组件：</p><ol><li><strong><code>char[] value</code> (字符数组)：</strong> 它的肚子里藏着一个真实的、长度比实际内容要长一些的字符数组（通常叫作容量 Capacity）。</li><li><strong><code>int count</code> (指针/计数器)：</strong> 记录当前数组里真正写入了几个字符。</li></ol><p><strong>光速操作的秘密：</strong></p><ul><li><strong>追加 (<code>append</code>)：</strong> 只是在 <code>value[count]</code> 的位置写下新字符，然后 <code>count++</code>。时间复杂度 <strong>O(1)</strong>。只有当数组真的装满了，它才会自动申请一个更大的新数组并把数据搬过去（扩容）。</li><li><strong>删尾巴 (<code>deleteCharAt</code>)：</strong> 根本没有物理擦除！只是把指针往回拨一格 <code>count--</code>。下次再追加时，新字符会直接覆盖在这个“废弃”的位置上。时间复杂度 <strong>O(1)</strong>。</li></ul><hr><h2 id="⚔️-字符串三剑客对比-高频面试题" tabindex="-1">⚔️ 字符串三剑客对比 (高频面试题) <a class="header-anchor" href="#⚔️-字符串三剑客对比-高频面试题" aria-label="Permalink to &quot;⚔️ 字符串三剑客对比 (高频面试题)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;"><code>String</code></th><th style="text-align:left;"><code>StringBuilder</code></th><th style="text-align:left;"><code>StringBuffer</code></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>可变性</strong></td><td style="text-align:left;"><strong>不可变</strong> (每次修改都会 new 新对象)</td><td style="text-align:left;"><strong>可变</strong> (在原数组上修改)</td><td style="text-align:left;"><strong>可变</strong> (在原数组上修改)</td></tr><tr><td style="text-align:left;"><strong>线程安全</strong></td><td style="text-align:left;">线程安全 (因为不可变)</td><td style="text-align:left;"><strong>非线程安全</strong> (没有加锁，单线程下速度最快)</td><td style="text-align:left;"><strong>线程安全</strong> (内部方法加了 <code>synchronized</code> 锁)</td></tr><tr><td style="text-align:left;"><strong>执行效率</strong></td><td style="text-align:left;">极低 (频繁拼接时)</td><td style="text-align:left;"><strong>极高</strong> (绝对的性能王者)</td><td style="text-align:left;">较低 (因为有锁的开销)</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">少量字符串操作、作为 HashMap 的 Key</td><td style="text-align:left;"><strong>绝大多数的字符串拼接、算法题</strong></td><td style="text-align:left;">多线程并发修改同一个字符串</td></tr></tbody></table><hr><h2 id="💻-核心-api-兵器谱-常用方法" tabindex="-1">💻 核心 API 兵器谱 (常用方法) <a class="header-anchor" href="#💻-核心-api-兵器谱-常用方法" aria-label="Permalink to &quot;💻 核心 API 兵器谱 (常用方法)&quot;">​</a></h2><p>在日常开发和算法题中，掌握以下几个方法就足够你横着走了：</p><h3 id="_1-增-append-insert" tabindex="-1">1. 增 (Append / Insert) <a class="header-anchor" href="#_1-增-append-insert" aria-label="Permalink to &quot;1. 增 (Append / Insert)&quot;">​</a></h3><ul><li><code>sb.append(xxx)</code>：在尾部追加。支持几乎所有数据类型 (int, char, String, 甚至 Object)。</li><li><code>sb.insert(int offset, xxx)</code>：在指定索引 <code>offset</code> 的位置强行插入一段内容，后面的字符会自动后挪。</li></ul><h3 id="_2-删-delete" tabindex="-1">2. 删 (Delete) <a class="header-anchor" href="#_2-删-delete" aria-label="Permalink to &quot;2. 删 (Delete)&quot;">​</a></h3><ul><li><code>sb.deleteCharAt(int index)</code>：删除指定座位上的单个字符。（回溯法最常用的“光速切尾巴”操作就是 <code>sb.deleteCharAt(sb.length() - 1)</code>）。</li><li><code>sb.delete(int start, int end)</code>：删除一个区间的内容。<strong>注意：左闭右开 <code>[start, end)</code></strong>。</li></ul><h3 id="_3-改-set-replace" tabindex="-1">3. 改 (Set / Replace) <a class="header-anchor" href="#_3-改-set-replace" aria-label="Permalink to &quot;3. 改 (Set / Replace)&quot;">​</a></h3><ul><li><code>sb.setCharAt(int index, char ch)</code>：把指定座位上的字符直接替换成新的字符。</li><li><code>sb.replace(int start, int end, String str)</code>：把指定区间的内容替换成另一段字符串。</li></ul><h3 id="_4-查与转换-get-convert" tabindex="-1">4. 查与转换 (Get / Convert) <a class="header-anchor" href="#_4-查与转换-get-convert" aria-label="Permalink to &quot;4. 查与转换 (Get / Convert)&quot;">​</a></h3><ul><li><code>sb.charAt(int index)</code>：查看指定座位上的字符是什么。</li><li><code>sb.length()</code>：获取当前真正装了多少个字符。</li><li><code>sb.toString()</code>：<strong>终极结算！</strong> 将当前的 <code>StringBuilder</code> 固化，生成一个真正的 <code>String</code> 对象并返回。</li></ul><h3 id="_5-逆天神技-reverse" tabindex="-1">5. 逆天神技 (Reverse) <a class="header-anchor" href="#_5-逆天神技-reverse" aria-label="Permalink to &quot;5. 逆天神技 (Reverse)&quot;">​</a></h3><ul><li><code>sb.reverse()</code>：将整个字符串<strong>原地倒序反转</strong>。这是 <code>String</code> 根本没有的方法，遇到反转字符串的题目直接调用，降维打击。</li></ul><hr><h2 id="📝-最佳实践与避坑指南" tabindex="-1">📝 最佳实践与避坑指南 <a class="header-anchor" href="#📝-最佳实践与避坑指南" aria-label="Permalink to &quot;📝 最佳实践与避坑指南&quot;">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">预分配容量 (极致优化)</p><p>如果你在使用前，<strong>大概知道这个字符串最终会有多长</strong>（比如生成长度为 n 的括号，最终长度是 2n），最好在创建时直接告诉它： <code>StringBuilder sb = new StringBuilder(2 * n);</code> 这样可以避免它在运行过程中因为数组不够大而触发“自动扩容（申请新数组 + 复制老数据）”，把性能压榨到极限。</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">误区：不要在 StringBuilder 里面用 `+`</p><p>❌ 错误示范：<code>sb.append(a + &quot;:&quot; + b);</code> 这样写会导致内部先生成隐式的 <code>StringBuilder</code> 去拼接 <code>a</code> 和 <code>b</code>，然后再交给外层的 <code>sb</code>。 ✅ 正确示范：<code>sb.append(a).append(&quot;:&quot;).append(b);</code> (链式调用，丝滑且没有任何额外开销)。</p></div><hr>',29)])])}const p=e(d,[["render",l]]);export{u as __pageData,p as default};
